patch:
diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 3f3f6c6e0d1a..ed580071902d 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -4629,8 +4629,12 @@ static Value *simplifySelectInst(Value *Cond, Value *TrueVal, Value *FalseVal,
     if (match(TrueVal, m_ZeroInt()))
       return ConstantInt::getFalse(Cond->getType());
   }
+  // select (select X, Y, false), true, Y -> Y
+  Value *X, *Y;
+  if (match(Cond, m_Select(m_Value(X), m_Value(Y), m_Zero())) &&
+      match(TrueVal, m_One()) && match(FalseVal, m_Specific(Y)))
+    return Y;

-  // If the true or false value is poison, we can fold to the other value.
   // If the true or false value is undef, we can fold to the other value as
   // long as the other value isn't poison.
   // select ?, poison, X -> X
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index e7d8208f94fd..b1f063012e88 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -2849,6 +2849,12 @@ Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {
   // checks whether folding it does not convert a well-defined value into
   // poison.
   if (match(TrueVal, m_One())) {
+    // select (select a, b, false), true, b -> b
+    Value *A2, *B2;
+    if (match(CondVal, m_Select(m_Value(A2), m_Value(B2), m_Zero())) &&
+        match(FalseVal, m_Specific(B2)))
+      return replaceInstUsesWith(SI, B2);
+
     if (impliesPoison(FalseVal, CondVal)) {
       // Change: A = select B, true, C --> A = or B, C
       return BinaryOperator::CreateOr(CondVal, FalseVal);

